write('lib/types.ts', '\nexport type Pick = "1" | "X" | "2";\n\nexport type Match = {\n  id: string;\n  home: string;\n  away: string;\n  label: string;\n  order: number;\n  officialMatchNo?: number;\n  group?: string;\n  date?: string;\n  timeEt?: string;\n  timeLocal?: string;\n  venue?: string;\n  city?: string;\n};\n\nexport type Prediction = {\n  matchId: string;\n  player: string;\n  pick: Pick;\n};\n\nexport type MatchResult = {\n  homeGoals: number;\n  awayGoals: number;\n  status?: "SCHEDULED" | "LIVE" | "FINISHED";\n  minute?: number;\n  updatedAt?: string;\n};\n\nexport type ScoredPrediction = Prediction & {\n  match: Match;\n  result?: MatchResult;\n  actual?: Pick;\n  points: number;\n  isCorrect: boolean | null;\n};\n\nexport type Standing = {\n  player: string;\n  points: number;\n  played: number;\n  correct: number;\n  pending: number;\n  percentage: number;\n};\n\nexport type PlayerSummary = Standing & {\n  totalPredictions: number;\n  wrong: number;\n};\n')
write('lib/format.ts', '\nimport type { MatchResult, Pick } from "./types";\n\nexport function pickLabel(pick?: Pick): string {\n  if (!pick) return "—";\n  if (pick === "1") return "1";\n  if (pick === "2") return "2";\n  return "X";\n}\n\nexport function resultLabel(result?: MatchResult): string {\n  if (!result) return "Pendiente";\n  return `${result.homeGoals}-${result.awayGoals}`;\n}\n\nexport function normalizePlayerForUrl(player: string): string {\n  return encodeURIComponent(player);\n}\n\nexport function formatMatchDate(date?: string): string {\n  if (!date) return "Fecha pendiente";\n\n  const parsed = new Date(`${date}T12:00:00`);\n  return new Intl.DateTimeFormat("es-ES", {\n    weekday: "short",\n    day: "numeric",\n    month: "short",\n  }).format(parsed);\n}\n\nexport function formatLongMatchDate(date?: string): string {\n  if (!date) return "Fecha pendiente";\n\n  const parsed = new Date(`${date}T12:00:00`);\n  return new Intl.DateTimeFormat("es-ES", {\n    weekday: "long",\n    day: "numeric",\n    month: "long",\n  }).format(parsed);\n}\n')
write('lib/scoring.ts', '\nimport matches from "@/data/matches.json";\nimport predictions from "@/data/predictions.json";\nimport players from "@/data/players.json";\nimport { manualResults } from "@/data/manualResults";\nimport type { Match, MatchResult, Pick, PlayerSummary, Prediction, ScoredPrediction, Standing } from "./types";\n\nconst allMatches = matches as Match[];\nconst allPredictions = predictions as Prediction[];\nconst allPlayers = players as string[];\n\nexport function signFromResult(result?: MatchResult): Pick | undefined {\n  if (!result) return undefined;\n  if (result.homeGoals > result.awayGoals) return "1";\n  if (result.homeGoals < result.awayGoals) return "2";\n  return "X";\n}\n\nexport function scorePrediction(prediction: Prediction, result?: MatchResult): number {\n  const actual = signFromResult(result);\n  if (!actual) return 0;\n  return prediction.pick === actual ? 1 : 0;\n}\n\nexport function getResults(): Record<string, MatchResult> {\n  return manualResults;\n}\n\nexport function getMatches(): Match[] {\n  return [...allMatches].sort((a, b) => {\n    if (a.date !== b.date) return String(a.date).localeCompare(String(b.date));\n    return (a.officialMatchNo ?? a.order) - (b.officialMatchNo ?? b.order);\n  });\n}\n\nexport function getPlayers(): string[] {\n  return allPlayers;\n}\n\nexport function getPredictions(): Prediction[] {\n  return allPredictions;\n}\n\nexport function getMatchesByDate(): Array<[string, Match[]]> {\n  const grouped = new Map<string, Match[]>();\n\n  for (const match of getMatches()) {\n    const key = match.date ?? "Fecha pendiente";\n    const list = grouped.get(key) ?? [];\n    list.push(match);\n    grouped.set(key, list);\n  }\n\n  return [...grouped.entries()];\n}\n\nexport function getScoredPredictions(results = getResults()): ScoredPrediction[] {\n  const matchById = new Map(allMatches.map((match) => [match.id, match]));\n\n  return allPredictions.map((prediction) => {\n    const match = matchById.get(prediction.matchId);\n    if (!match) {\n      throw new Error(`Missing match ${prediction.matchId}`);\n    }\n\n    const result = results[prediction.matchId];\n    const actual = signFromResult(result);\n    const points = scorePrediction(prediction, result);\n\n    return {\n      ...prediction,\n      match,\n      result,\n      actual,\n      points,\n      isCorrect: actual ? prediction.pick === actual : null,\n    };\n  });\n}\n\nexport function getStandings(results = getResults()): Standing[] {\n  const scored = getScoredPredictions(results);\n  const table = new Map<string, Standing>();\n\n  for (const player of allPlayers) {\n    table.set(player, {\n      player,\n      points: 0,\n      played: 0,\n      correct: 0,\n      pending: allMatches.length,\n      percentage: 0,\n    });\n  }\n\n  for (const item of scored) {\n    const row = table.get(item.player);\n    if (!row) continue;\n\n    if (item.actual) {\n      row.played += 1;\n      row.pending -= 1;\n      row.points += item.points;\n      if (item.isCorrect) row.correct += 1;\n    }\n  }\n\n  return [...table.values()]\n    .map((row) => ({\n      ...row,\n      percentage: row.played > 0 ? Math.round((row.correct / row.played) * 100) : 0,\n    }))\n    .sort((a, b) => {\n      if (b.points !== a.points) return b.points - a.points;\n      if (b.percentage !== a.percentage) return b.percentage - a.percentage;\n      return a.player.localeCompare(b.player, "es");\n    });\n}\n\nexport function getPlayerSummary(player: string, results = getResults()): PlayerSummary {\n  const row = getStandings(results).find((item) => item.player === player) ?? {\n    player,\n    points: 0,\n    played: 0,\n    correct: 0,\n    pending: allMatches.length,\n    percentage: 0,\n  };\n\n  return {\n    ...row,\n    totalPredictions: allMatches.length,\n    wrong: row.played - row.correct,\n  };\n}\n\nexport function getPlayerSummaries(results = getResults()): PlayerSummary[] {\n  return allPlayers\n    .map((player) => getPlayerSummary(player, results))\n    .sort((a, b) => {\n      if (b.points !== a.points) return b.points - a.points;\n      return a.player.localeCompare(b.player, "es");\n    });\n}\n\nexport function getPlayerPredictions(player: string, results = getResults()): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.player.toLowerCase() === decodeURIComponent(player).toLowerCase())\n    .sort((a, b) => {\n      if (a.match.date !== b.match.date) return String(a.match.date).localeCompare(String(b.match.date));\n      return (a.match.officialMatchNo ?? a.match.order) - (b.match.officialMatchNo ?? b.match.order);\n    });\n}\n\nexport function getMatchPredictions(matchId: string, results = getResults()): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.matchId === matchId)\n    .sort((a, b) => a.player.localeCompare(b.player, "es"));\n}\n')
write('components/BottomNav.tsx', '\nimport Link from "next/link";\n\nexport function BottomNav() {\n  return (\n    <nav className="bottom-nav">\n      <Link href="/">Ranking</Link>\n      <Link href="/partidos">Partidos</Link>\n      <Link href="/pronosticos">Pronósticos</Link>\n    </nav>\n  );\n}\n')
write('components/StandingCard.tsx', '\nimport Link from "next/link";\nimport type { Standing } from "@/lib/types";\nimport { normalizePlayerForUrl } from "@/lib/format";\n\nexport function StandingCard({ row, position }: { row: Standing; position: number }) {\n  return (\n    <Link href={`/pronosticos/${normalizePlayerForUrl(row.player)}`} className="standing-card">\n      <div className="rank">{position}</div>\n      <div className="standing-main">\n        <div className="standing-name">{row.player}</div>\n        <div className="muted">\n          {row.played === 0\n            ? "72 pronósticos pendientes"\n            : `${row.correct}/${row.played} aciertos · ${row.pending} pendientes`}\n        </div>\n      </div>\n      <div className="points">{row.points}</div>\n    </Link>\n  );\n}\n')
write('components/MatchCard.tsx', '\nimport { formatMatchDate, resultLabel } from "@/lib/format";\nimport { getMatchPredictions, signFromResult } from "@/lib/scoring";\nimport type { Match, MatchResult } from "@/lib/types";\n\nexport function MatchCard({\n  match,\n  result,\n}: {\n  match: Match;\n  result?: MatchResult;\n}) {\n  const actual = signFromResult(result);\n  const predictions = getMatchPredictions(match.id);\n\n  const counts = predictions.reduce(\n    (acc, item) => {\n      acc[item.pick] += 1;\n      return acc;\n    },\n    { "1": 0, X: 0, "2": 0 } as Record<"1" | "X" | "2", number>\n  );\n\n  return (\n    <article className="match-card">\n      <div className="match-top">\n        <div>\n          <div className="meta-row">\n            <span>{formatMatchDate(match.date)}</span>\n            <span className="group-chip">Grupo {match.group ?? "—"}</span>\n          </div>\n          <div className="match-label">{match.home} - {match.away}</div>\n          <div className="muted">\n            {match.city}\n            {match.timeLocal ? ` · ${match.timeLocal} local` : ""}\n          </div>\n        </div>\n        <div className={result ? "score done" : "score"}>{resultLabel(result)}</div>\n      </div>\n\n      <div className="pick-row">\n        <span className={actual === "1" ? "chip hit" : "chip"}>1 · {counts["1"]}</span>\n        <span className={actual === "X" ? "chip hit" : "chip"}>X · {counts.X}</span>\n        <span className={actual === "2" ? "chip hit" : "chip"}>2 · {counts["2"]}</span>\n      </div>\n    </article>\n  );\n}\n')
write('app/partidos/page.tsx', '\nimport { MatchCard } from "@/components/MatchCard";\nimport { formatLongMatchDate } from "@/lib/format";\nimport { getMatchesByDate, getResults } from "@/lib/scoring";\n\nexport default function MatchesPage() {\n  const groupedMatches = getMatchesByDate();\n  const results = getResults();\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Partidos</h1>\n        <p>Calendario de la primera fase, con grupo, fecha y pronósticos 1/X/2.</p>\n      </div>\n\n      <div className="stack">\n        {groupedMatches.map(([date, matches]) => (\n          <section key={date} className="date-section">\n            <h2 className="date-heading">{formatLongMatchDate(date)}</h2>\n            <div className="stack">\n              {matches.map((match) => (\n                <MatchCard key={match.id} match={match} result={results[match.id]} />\n              ))}\n            </div>\n          </section>\n        ))}\n      </div>\n    </section>\n  );\n}\n')
write('app/pronosticos/page.tsx', '\nimport Link from "next/link";\nimport { normalizePlayerForUrl } from "@/lib/format";\nimport { getPlayerSummaries } from "@/lib/scoring";\n\nexport default function PredictionsPage() {\n  const players = getPlayerSummaries();\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Pronósticos</h1>\n        <p>La quiniela individual de cada jugador.</p>\n      </div>\n\n      <div className="grid-list">\n        {players.map((row) => (\n          <Link key={row.player} href={`/pronosticos/${normalizePlayerForUrl(row.player)}`} className="player-tile">\n            <span>{row.player}</span>\n            <div className="pronostic-summary">\n              {row.played === 0 ? (\n                <>72 pendientes</>\n              ) : (\n                <>{row.correct} aciertos · {row.wrong} fallos</>\n              )}\n            </div>\n          </Link>\n        ))}\n      </div>\n    </section>\n  );\n}\n')
write('app/pronosticos/[player]/page.tsx', '\nimport Link from "next/link";\nimport { notFound } from "next/navigation";\nimport { formatMatchDate, resultLabel } from "@/lib/format";\nimport { getPlayerPredictions, getPlayerSummary, getPlayers, getResults } from "@/lib/scoring";\n\nexport function generateStaticParams() {\n  return getPlayers().map((player) => ({ player }));\n}\n\nexport default async function PlayerPredictionPage({\n  params,\n}: {\n  params: Promise<{ player: string }>;\n}) {\n  const { player: rawPlayer } = await params;\n  const player = decodeURIComponent(rawPlayer);\n\n  const predictions = getPlayerPredictions(player);\n  if (predictions.length === 0) notFound();\n\n  const summary = getPlayerSummary(player);\n  const results = getResults();\n\n  return (\n    <section>\n      <div className="page-header">\n        <Link href="/pronosticos" className="back">← Pronósticos</Link>\n        <h1>{player}</h1>\n        <p>\n          {summary.played === 0\n            ? "72 pronósticos pendientes"\n            : `${summary.correct} aciertos · ${summary.wrong} fallos · ${summary.pending} pendientes`}\n        </p>\n      </div>\n\n      <div className="stack">\n        {predictions.map((item) => (\n          <article key={item.matchId} className="prediction-card">\n            <div>\n              <div className="meta-row">\n                <span>{formatMatchDate(item.match.date)}</span>\n                <span className="group-chip">Grupo {item.match.group ?? "—"}</span>\n              </div>\n              <div className="match-label">{item.match.label}</div>\n              <div className="muted">Resultado: {resultLabel(results[item.matchId])}</div>\n            </div>\n            <div className="prediction-right">\n              <span className="chip">{item.pick}</span>\n              {item.isCorrect === null ? (\n                <span className="pill pending">Pendiente</span>\n              ) : item.isCorrect ? (\n                <span className="pill ok">+1</span>\n              ) : (\n                <span className="pill ko">0</span>\n              )}\n            </div>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n')
write('app/jugadores/page.tsx', '\nimport { redirect } from "next/navigation";\n\nexport default function PlayersPage() {\n  redirect("/pronosticos");\n}\n')
write('app/jugador/[player]/page.tsx', '\nimport { redirect } from "next/navigation";\n\nexport default async function OldPlayerPage({\n  params,\n}: {\n  params: Promise<{ player: string }>;\n}) {\n  const { player } = await params;\n  redirect(`/pronosticos/${encodeURIComponent(player)}`);\n}\n')
write('app/admin/page.tsx', '\nimport { getMatches } from "@/lib/scoring";\n\nexport default function AdminPage() {\n  const matches = getMatches();\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Admin</h1>\n        <p>\n          Pantalla oculta para resultados manuales. Por ahora se editan en <code>data/manualResults.ts</code>.\n          Después podemos sustituir esto por un formulario protegido con PIN.\n        </p>\n      </div>\n\n      <div className="code-card">\n        <p>Ejemplo:</p>\n        <pre>{`export const manualResults = {\n  m01: { homeGoals: 2, awayGoals: 1 },\n  m02: { homeGoals: 0, awayGoals: 0 },\n};`}</pre>\n      </div>\n\n      <div className="stack">\n        {matches.map((match) => (\n          <article key={match.id} className="admin-row">\n            <code>{match.id}</code>\n            <span>{match.label} · Grupo {match.group} · {match.date}</span>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n')
css_path = ROOT / "app/globals.css"
if css_path.exists():
    css = css_path.read_text(encoding="utf-8")
    css = css.replace("grid-template-columns: repeat(4, 1fr);", "grid-template-columns: repeat(3, 1fr);")
    additions = '\n\n.meta-row {\n  display: flex;\n  align-items: center;\n  flex-wrap: wrap;\n  gap: 7px;\n  margin-bottom: 5px;\n  color: var(--muted);\n  font-size: 12px;\n  font-weight: 750;\n}\n\n.group-chip {\n  display: inline-flex;\n  align-items: center;\n  min-height: 22px;\n  padding: 3px 8px;\n  border-radius: 999px;\n  background: #fff7dc;\n  color: #d59609;\n  font-size: 12px;\n  font-weight: 850;\n}\n\n.date-section {\n  display: grid;\n  gap: 10px;\n}\n\n.date-heading {\n  margin: 8px 2px 0;\n  color: var(--muted);\n  font-size: 14px;\n  font-weight: 850;\n  text-transform: capitalize;\n}\n\n.pronostic-summary {\n  margin-top: 8px;\n  color: var(--muted);\n  font-size: 13px;\n  font-weight: 700;\n}\n'
    if ".meta-row" not in css:
        css = css.rstrip() + additions + "\n"
    css_path.write_text(css, encoding="utf-8")
print("Versión 2 limpia aplicada.")
